import copy
from collections import Counter, deque

def solve(grid):
    """Diamond shapes on checkerboard - extend rays from edge endpoints."""
    rows, cols = len(grid), len(grid[0])
    out = copy.deepcopy(grid)

    special = {}
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] not in (0, 1):
                special[(r,c)] = grid[r][c]

    visited = set()
    diamonds = []
    for (r,c) in special:
        if (r,c) in visited:
            continue
        stack = [(r,c)]
        comp = set()
        while stack:
            cr2, cc2 = stack.pop()
            if (cr2,cc2) in comp:
                continue
            comp.add((cr2,cc2))
            for dr, dc in [(-1,-1),(-1,1),(1,-1),(1,1)]:
                nr, nc = cr2+dr, cc2+dc
                if (nr,nc) in special and (nr,nc) not in comp:
                    stack.append((nr,nc))
        visited |= comp
        diamonds.append(comp)

    for diamond in diamonds:
        center_r = sum(r for r,c in diamond) / len(diamond)
        center_c = sum(c for r,c in diamond) / len(diamond)

        colors = Counter(special[(r,c)] for r,c in diamond)
        interior_color = colors.most_common(1)[0][0]

        border_cells = {(r,c): special[(r,c)] for (r,c) in diamond if special[(r,c)] != interior_color}

        used = set()
        segments = []

        for (r,c) in sorted(border_cells.keys()):
            if (r,c) in used:
                continue
            color = border_cells[(r,c)]
            for dr, dc in [(1,1), (1,-1)]:
                seg = [(r,c)]
                rr, cc2 = r+dr, c+dc
                while (rr,cc2) in border_cells and border_cells[(rr,cc2)] == color:
                    seg.append((rr,cc2))
                    rr += dr; cc2 += dc
                rr, cc2 = r-dr, c-dc
                while (rr,cc2) in border_cells and border_cells[(rr,cc2)] == color:
                    seg.insert(0, (rr,cc2))
                    rr -= dr; cc2 -= dc

                if len(seg) >= 2:
                    seg_set = frozenset(seg)
                    if not any(frozenset(s[0]) == seg_set for s in segments):
                        segments.append((seg, color, (dr, dc)))
                        for p in seg:
                            used.add(p)
                    break
            else:
                used.add((r,c))

        for seg, color, (dr, dc) in segments:
            if (dr, dc) == (1, 1):
                perps = [(-1, 1), (1, -1)]
            else:
                perps = [(1, 1), (-1, -1)]

            mid_r = (seg[0][0] + seg[-1][0]) / 2
            mid_c = (seg[0][1] + seg[-1][1]) / 2

            outward = None
            for perp in perps:
                test_r = mid_r + perp[0]
                test_c = mid_c + perp[1]
                dist_orig = (mid_r - center_r)**2 + (mid_c - center_c)**2
                dist_new = (test_r - center_r)**2 + (test_c - center_c)**2
                if dist_new > dist_orig:
                    outward = perp
                    break

            if outward is None:
                outward = perps[0]

            for endpoint in [seg[0], seg[-1]]:
                rr, cc2 = endpoint
                while True:
                    rr += outward[0]
                    cc2 += outward[1]
                    if rr < 0 or rr >= rows or cc2 < 0 or cc2 >= cols:
                        break
                    if (rr, cc2) in special:
                        break
                    if out[rr][cc2] == 1:
                        out[rr][cc2] = color

    return out

