import copy
from collections import Counter, deque

def solve(grid):
    """Move 4s in direction indicated by template, until adjacent to wall."""
    rows, cols = len(grid), len(grid[0])
    out = copy.deepcopy(grid)

    flat = [grid[r][c] for r in range(rows) for c in range(cols)]
    bg = Counter(flat).most_common(1)[0][0]

    # Find all potential wall colors (any non-bg, non-4, non-0 color)
    all_colors = set()
    for r in range(rows):
        for c in range(cols):
            v = grid[r][c]
            if v not in (bg, 4, 0):
                all_colors.add(v)

    wall_colors = set()
    templates = {}

    for wc in all_colors:
        wc_cells = set()
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == wc:
                    wc_cells.add((r, c))

        visited = set()
        for start in sorted(wc_cells):
            if start in visited:
                continue
            comp = set()
            q = deque([start])
            while q:
                rr, cc = q.popleft()
                if (rr, cc) in comp:
                    continue
                comp.add((rr, cc))
                for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                    nr, nc = rr+dr, cc+dc
                    if (nr, nc) in wc_cells and (nr, nc) not in comp:
                        q.append((nr, nc))
            visited |= comp

            min_r = min(r for r, c in comp)
            max_r = max(r for r, c in comp)
            min_c = min(c for r, c in comp)
            max_c = max(c for r, c in comp)

            has_interior = False
            interior_cells_2 = []
            for r in range(min_r, max_r + 1):
                for c in range(min_c, max_c + 1):
                    if grid[r][c] in (1, 2):
                        has_interior = True
                        if grid[r][c] == 2:
                            interior_cells_2.append((r - min_r, c - min_c))

            if has_interior and interior_cells_2:
                int_min_r = min_r + 1
                int_max_r = max_r - 1
                int_min_c = min_c + 1
                int_max_c = max_c - 1

                center_r = (int_min_r + int_max_r) / 2.0 - min_r
                center_c = (int_min_c + int_max_c) / 2.0 - min_c

                avg_r = sum(r for r, c in interior_cells_2) / len(interior_cells_2)
                avg_c = sum(c for r, c in interior_cells_2) / len(interior_cells_2)

                dr = avg_r - center_r
                dc = avg_c - center_c

                dir_r = 0 if abs(dr) < 0.3 else (1 if dr > 0 else -1)
                dir_c = 0 if abs(dc) < 0.3 else (1 if dc > 0 else -1)

                templates[wc] = (dir_r, dir_c)
                wall_colors.add(wc)

    fours = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 4:
                fours.append((r, c))

    for r, c in fours:
        # Determine wall color by scanning cardinal directions
        # Use the nearest wall in each cardinal direction
        wall_votes = Counter()
        for ddr, ddc in [(0,1),(0,-1),(1,0),(-1,0)]:
            rr, cc = r + ddr, c + ddc
            while 0 <= rr < rows and 0 <= cc < cols:
                if grid[rr][cc] in wall_colors:
                    wall_votes[grid[rr][cc]] += 1
                    break
                elif grid[rr][cc] not in (bg, 4, 0):
                    break
                rr += ddr
                cc += ddc
        wall_color = wall_votes.most_common(1)[0][0] if wall_votes else None

        if wall_color is None or wall_color not in templates:
            continue

        dir_r, dir_c = templates[wall_color]

        if dir_r == 0 and dir_c == 0:
            continue

        out[r][c] = bg

        nr, nc = r, c
        while True:
            nnr, nnc = nr + dir_r, nc + dir_c
            if nnr < 0 or nnr >= rows or nnc < 0 or nnc >= cols:
                break
            if grid[nnr][nnc] == wall_color:
                break
            nr, nc = nnr, nnc

        out[nr][nc] = 4

    return out
